from google.cloud import firestore
from google.cloud import pubsub_v1
from google.cloud import storage
import base64
import json

def process_file(data, context):
    # Initialize clients
    db = firestore.Client()
    pubsub_publisher = pubsub_v1.PublisherClient()
    storage_client = storage.Client()

    # Get file details from the event data
    bucket_name = data['bucket']
    file_name = data['name']

    # Download the file from Cloud Storage
    bucket = storage_client.get_bucket(bucket_name)
    blob = bucket.blob(file_name)
    content = blob.download_as_text()

    # Process the file content (example: parse JSON)
    try:
        parsed_data = json.loads(content)
    except json.JSONDecodeError as e:
        print(f"Failed to decode JSON: {e}")
        return

    # Write data to Firestore
    db.collection('processed_files').document(file_name).set(parsed_data)

    # Publish processed data to Pub/Sub
    topic_path = pubsub_publisher.topic_path('your-project-id', 'your-topic-name')
    message = json.dumps(parsed_data).encode()
    future = pubsub_publisher.publish(topic_path, message)
    print(f"Published message ID {future.result()}")

    return f"Processed file: {file_name}"